          <div className="flex justify-between text-slate-900 font-bold text-xl bg-slate-100 p-3 rounded-lg">
            <span>{t('billing_invoice_balance')}</span>
            <span>${(bill.totalAmount - (bill.paidAmount || 0)).toFixed(2)}</span>
          </div>
