                                      <td className="px-6 py-3 text-sm">{t.method}</td>
                                      <td className={`px-6 py-3 text-sm font-bold text-right ${t.type === 'income' ? 'text-green-600' : 'text-red-600'}`}>
                                          {t.type === 'income' ? '+' : '-'}${t.amount.toLocaleString()}
